                        m_AlphaHitTestMinimumThreshold = 0;
                    }
                }

                bool SpriteSupportsAlphaHitTest()
                {
                    return m_Sprite != null && m_Sprite.texture != null && !GraphicsFormatUtility.IsCrunchFormat(m_Sprite.texture.format) && m_Sprite.texture.isReadable;
                }
            }
        }


